import{_ as o,o as a,c as r,ae as n}from"./chunks/framework.C8MNLDzb.js";const d=JSON.parse('{"title":"典故溯源","description":"","frontmatter":{},"headers":[],"relativePath":"docs/典故溯源.md","filePath":"docs/典故溯源.md"}'),s={name:"docs/典故溯源.md"};function e(h,t,g,u,q,i){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="典故溯源" tabindex="-1">典故溯源 <a class="header-anchor" href="#典故溯源" aria-label="Permalink to &quot;典故溯源&quot;">​</a></h1><blockquote><p>常用典故的出处与演变，按主题分类整理。</p></blockquote><h2 id="仁义道德" tabindex="-1">仁义道德 <a class="header-anchor" href="#仁义道德" aria-label="Permalink to &quot;仁义道德&quot;">​</a></h2><h3 id="桃花源" tabindex="-1">桃花源 <a class="header-anchor" href="#桃花源" aria-label="Permalink to &quot;桃花源&quot;">​</a></h3><p><strong>出处：</strong> 陶渊明《桃花源记》 <strong>内容：</strong> 武陵渔人误入一处世外桃源，居民安居乐业，不知有汉魏。后人以&quot;桃花源&quot;比喻理想中的安定社会。 <strong>原文摘录：</strong> &quot;土地平旷，屋舍俨然，有良田、美池、桑竹之属。阡陌交通，鸡犬相闻。&quot;</p><h3 id="洛阳纸贵" tabindex="-1">洛阳纸贵 <a class="header-anchor" href="#洛阳纸贵" aria-label="Permalink to &quot;洛阳纸贵&quot;">​</a></h3><p><strong>出处：</strong> 《晋书·文苑传》 <strong>内容：</strong> 左思《三都赋》写成后，豪贵之家争相传抄，致使洛阳纸张供不应求，价格飞涨。比喻作品风靡一时。 <strong>原文摘录：</strong> &quot;豪贵之家，竞相传写，洛阳为之纸贵。&quot;</p><h3 id="负荆请罪" tabindex="-1">负荆请罪 <a class="header-anchor" href="#负荆请罪" aria-label="Permalink to &quot;负荆请罪&quot;">​</a></h3><p><strong>出处：</strong> 司马迁《史记·廉颇蔺相如列传》 <strong>内容：</strong> 廉颇因蔺相如位在己上而不服，欲辱之。相如避让，国家为重。廉颇闻之，肉袒负荆，登门请罪。 <strong>原文摘录：</strong> &quot;廉颇闻之，肉袒负荆，因宾客至蔺相如门谢罪。&quot;</p><h3 id="卧薪尝胆" tabindex="-1">卧薪尝胆 <a class="header-anchor" href="#卧薪尝胆" aria-label="Permalink to &quot;卧薪尝胆&quot;">​</a></h3><p><strong>出处：</strong> 《史记·越王勾践世家》 <strong>内容：</strong> 越王勾践战败后，被迫为吴王夫差驾车养马。他卧薪尝胆，不忘复仇，最终灭吴复国。 <strong>原文摘录：</strong> &quot;吴既赦越，越王勾践反国，乃苦身焦思，置胆于坐，坐卧即仰胆，饮食亦尝胆也。&quot;</p><h3 id="四海之内皆兄弟" tabindex="-1">四海之内皆兄弟 <a class="header-anchor" href="#四海之内皆兄弟" aria-label="Permalink to &quot;四海之内皆兄弟&quot;">​</a></h3><p><strong>出处：</strong> 《论语·颜渊》 <strong>内容：</strong> 司马牛忧曰：&quot;人皆有兄弟，我独亡！&quot;子夏曰：&quot;商闻之矣：&#39;死生有命，富贵在天。&#39;君子敬而无失，与人恭而有礼，四海之内，皆兄弟也。&quot; <strong>原文摘录：</strong> &quot;君子敬而无失，与人恭而有礼，四海之内，皆兄弟也。&quot;</p><h2 id="志向抱负" tabindex="-1">志向抱负 <a class="header-anchor" href="#志向抱负" aria-label="Permalink to &quot;志向抱负&quot;">​</a></h2><h3 id="破釜沉舟" tabindex="-1">破釜沉舟 <a class="header-anchor" href="#破釜沉舟" aria-label="Permalink to &quot;破釜沉舟&quot;">​</a></h3><p><strong>出处：</strong> 《史记·项羽本纪》 <strong>内容：</strong> 巨鹿之战，项羽率楚军渡河后，凿沉船只，焚毁营垒，每人只带三日口粮，以示必死之心。终于大破秦军。 <strong>原文摘录：</strong> &quot;皆沉船，破釜甑，烧庐舍，持三日粮，以示士卒必死，无一还心。&quot;</p><h3 id="纸上谈兵" tabindex="-1">纸上谈兵 <a class="header-anchor" href="#纸上谈兵" aria-label="Permalink to &quot;纸上谈兵&quot;">​</a></h3><p><strong>出处：</strong> 《史记·廉颇蔺相如列传》 <strong>内容：</strong> 赵括自幼读兵书，谈兵事，其父赵奢不能应对。及代廉颇为将，在长平之战中被秦军大败。 <strong>原文摘录：</strong> &quot;赵括自少时学兵法，言兵事，以天下莫能当。&quot;</p><h3 id="完璧归赵" tabindex="-1">完璧归赵 <a class="header-anchor" href="#完璧归赵" aria-label="Permalink to &quot;完璧归赵&quot;">​</a></h3><p><strong>出处：</strong> 司马迁《史记·廉颇蔺相如列传》 <strong>内容：</strong> 蔺相如奉和氏璧出使秦国，秦王欲以强凌弱夺璧。相如以智勇双全，完璧归赵。 <strong>原文摘录：</strong> &quot;相如度秦王虽斋，决负约不偿城，乃使其从者衣褐，怀其璧，从径道亡，归璧于赵。&quot;</p><h3 id="退避三舍" tabindex="-1">退避三舍 <a class="header-anchor" href="#退避三舍" aria-label="Permalink to &quot;退避三舍&quot;">​</a></h3><p><strong>出处：</strong> 《左传·僖公二十三年》 <strong>内容：</strong> 晋文公重耳流亡楚国，楚成王问其何以报答。重耳答曰：&quot;若以君之灵，得反晋国，晋楚治兵，遇于中原，其辟君三舍。&quot;后晋楚战于城濮，晋文公果然退避三舍。 <strong>原文摘录：</strong> &quot;若以君之灵，得反晋国，晋楚治兵，遇于中原，其辟君三舍。&quot;</p><h3 id="望梅止渴" tabindex="-1">望梅止渴 <a class="header-anchor" href="#望梅止渴" aria-label="Permalink to &quot;望梅止渴&quot;">​</a></h3><p><strong>出处：</strong> 《世说新语·假谲》 <strong>内容：</strong> 曹操率军行军，士兵渴甚。操伪称前有梅林，士兵闻之口中生津，遂止渴以至无虞。 <strong>原文摘录：</strong> &quot;操军士皆口渴，操心念前有梅林，倏然一思，口中水出，遂得不渴。&quot;</p><h2 id="治学修身" tabindex="-1">治学修身 <a class="header-anchor" href="#治学修身" aria-label="Permalink to &quot;治学修身&quot;">​</a></h2><h3 id="韦编三绝" tabindex="-1">韦编三绝 <a class="header-anchor" href="#韦编三绝" aria-label="Permalink to &quot;韦编三绝&quot;">​</a></h3><p><strong>出处：</strong> 《史记·孔子世家》 <strong>内容：</strong> 孔子读《易》，韦编三绝。古代书写在竹简上，用皮绳编缀。韦编三绝比喻读书勤奋。 <strong>原文摘录：</strong> &quot;孔子晚而喜《易》，读《易》，韦编三绝。&quot;</p><h3 id="囊萤映雪" tabindex="-1">囊萤映雪 <a class="header-anchor" href="#囊萤映雪" aria-label="Permalink to &quot;囊萤映雪&quot;">​</a></h3><p><strong>出处：</strong> 《晋书·车胤传》《孙氏世录》 <strong>内容：</strong> 车胤家贫无灯，夏日捕萤火虫装入练囊以照明读书；孙康家贫无灯，冬天借雪光读书。后人合称&quot;囊萤映雪&quot;，比喻家贫苦读。 <strong>原文摘录：</strong> &quot;（车胤）家贫不常得油，夏月则练囊盛数十萤火以照书。&quot;</p><h3 id="悬梁刺股" tabindex="-1">悬梁刺股 <a class="header-anchor" href="#悬梁刺股" aria-label="Permalink to &quot;悬梁刺股&quot;">​</a></h3><p><strong>出处：</strong> 《太平御览》引《汉书》 <strong>内容：</strong> 孙敬好学，晨夕不休，及至疲困，乃以绳系头悬屋梁，睡则刺股。后以&quot;悬梁刺股&quot;形容刻苦自学。 <strong>原文摘录：</strong> &quot;孙敬字文宝，好学，晨夕不休。及至眠睡疲寝，以绳系头，悬屋梁，后为当世大儒。&quot;</p><h3 id="闻鸡起舞" tabindex="-1">闻鸡起舞 <a class="header-anchor" href="#闻鸡起舞" aria-label="Permalink to &quot;闻鸡起舞&quot;">​</a></h3><p><strong>出处：</strong> 《晋书·祖逖传》 <strong>内容：</strong> 祖逖与刘琨为友，共被同寝。中夜闻鸡鸣，逖蹴琨起，曰：&quot;此非恶声也！&quot;因起舞。后以&quot;闻鸡起舞&quot;比喻志士奋发。 <strong>原文摘录：</strong> &quot;逖与琨共被同寝，中夜闻鸡鸣，蹴琨觉，曰：&#39;此非恶声也！&#39;因起舞。&quot;</p><h3 id="邯郸学步" tabindex="-1">邯郸学步 <a class="header-anchor" href="#邯郸学步" aria-label="Permalink to &quot;邯郸学步&quot;">​</a></h3><p><strong>出处：</strong> 《庄子·秋水》 <strong>内容：</strong> 燕国有寿陵少年闻赵国邯郸人步姿优美，遂前往学习。结果未学成，反失其故步，只能匍匐而归。 <strong>原文摘录：</strong> &quot;且子独不闻夫寿陵余子之学行于邯郸与？未得国能，又失其故行矣，直匍匐而归耳。&quot;</p><h2 id="智慧谋略" tabindex="-1">智慧谋略 <a class="header-anchor" href="#智慧谋略" aria-label="Permalink to &quot;智慧谋略&quot;">​</a></h2><h3 id="草木皆兵" tabindex="-1">草木皆兵 <a class="header-anchor" href="#草木皆兵" aria-label="Permalink to &quot;草木皆兵&quot;">​</a></h3><p><strong>出处：</strong> 《晋书·苻坚载记》 <strong>内容：</strong> 苻坚在淝水之战前夕，登高望敌，见晋军阵容整齐，又远望八公山上的草木，皆似人形，以为晋兵。后以&quot;草木皆兵&quot;形容人在极度惊恐时，稍有动静即疑神疑鬼。 <strong>原文摘录：</strong> &quot;坚与苻融登城而望王师，见部阵齐整，将士精锐，又望八公山上草木，皆类人形，顾谓融曰：&#39;此亦勍敌也！&#39;&quot;</p><h3 id="暗度陈仓" tabindex="-1">暗度陈仓 <a class="header-anchor" href="#暗度陈仓" aria-label="Permalink to &quot;暗度陈仓&quot;">​</a></h3><p><strong>出处：</strong> 《史记·高祖本纪》 <strong>内容：</strong> 韩信明修栈道以疑敌，暗中绕道陈仓，突袭关中。后以&quot;暗度陈仓&quot;比喻表面故作姿态，暗中另有图谋。 <strong>原文摘录：</strong> &quot;去辄烧所过栈道，以备诸侯盗兵袭之，亦示项王汉中无东意。八月，汉王用韩信之计，从故道还袭雍王章邯。&quot;</p><h3 id="背水一战" tabindex="-1">背水一战 <a class="header-anchor" href="#背水一战" aria-label="Permalink to &quot;背水一战&quot;">​</a></h3><p><strong>出处：</strong> 《史记·淮阴侯列传》 <strong>内容：</strong> 韩信攻赵，令万人背水列阵。兵死战而后退入水边阵地，皆殊死战，大破赵军。 <strong>原文摘录：</strong> &quot;信乃使万人先行，出，背水阵。赵军望见而大笑。平旦，信建大将之旗鼓，鼓行出井陉口。&quot;</p><h3 id="调虎离山" tabindex="-1">调虎离山 <a class="header-anchor" href="#调虎离山" aria-label="Permalink to &quot;调虎离山&quot;">​</a></h3><p><strong>出处：</strong> 《三十六计》或《西游记》 <strong>内容：</strong> 迫使敌人离开有利地形的计谋。作战时，当敌居险守固，可设法诱其离开基地，乘机夺取要地。 <strong>原文摘录：</strong> &quot;待天以困之，用人以诱之。调虎离山，此之谓也。&quot;</p><h3 id="围魏救赵" tabindex="-1">围魏救赵 <a class="header-anchor" href="#围魏救赵" aria-label="Permalink to &quot;围魏救赵&quot;">​</a></h3><p><strong>出处：</strong> 《史记·孙子吴起列传》 <strong>内容：</strong> 战国时，魏国围攻赵国都城邯郸。齐国军师孙膑不直接救邯郸，而率军围攻魏国都城大梁，迫魏军回援，在桂陵伏击大胜。 <strong>原文摘录：</strong> &quot;善战者，其势险，其节短。攻其所必救，以逸待劳。&quot;</p><h3 id="三顾茅庐" tabindex="-1">三顾茅庐 <a class="header-anchor" href="#三顾茅庐" aria-label="Permalink to &quot;三顾茅庐&quot;">​</a></h3><p><strong>出处：</strong> 《三国志·蜀书·诸葛亮传》 <strong>内容：</strong> 刘备三次前往隆中拜访诸葛亮，请其出山辅佐。形容求贤若渴，诚意殷切。 <strong>原文摘录：</strong> &quot;先帝不以臣卑鄙，猥自枉屈，三顾臣于草庐之中，咨臣以当世之事。&quot;</p><h3 id="塞翁失马" tabindex="-1">塞翁失马 <a class="header-anchor" href="#塞翁失马" aria-label="Permalink to &quot;塞翁失马&quot;">​</a></h3><p><strong>出处：</strong> 《淮南子·人间训》 <strong>内容：</strong> 边塞老翁的马跑入胡地，人皆吊之。翁曰：&quot;此何遽不能为福乎？&quot;后马带胡骏马而归，人皆贺之。比喻祸福相依，坏事可能变好事。 <strong>原文摘录：</strong> &quot;近塞上之人，有善术者，马无故而入胡，人皆吊之。其父曰：&#39;此何遽不能为福乎？&#39;&quot;</p><h3 id="愚公移山" tabindex="-1">愚公移山 <a class="header-anchor" href="#愚公移山" aria-label="Permalink to &quot;愚公移山&quot;">​</a></h3><p><strong>出处：</strong> 《列子·汤问》 <strong>内容：</strong> 愚公因太行、王屋二山阻塞出入，决心子子孙孙挖山不止。智叟笑其迂愚，愚公答曰：&quot;我死有子，子又有孙，孙又生子，子子孙孙无穷匮也，而山不加增，何苦而不平？&quot; <strong>原文摘录：</strong> &quot;虽我之死，有子存焉；子又生孙，孙又生子；子又有子，子又有孙；子子孙孙无穷匮也，而山不加增，何苦而不平？&quot;</p><h3 id="塞上曲-李广" tabindex="-1">塞上曲（李广） <a class="header-anchor" href="#塞上曲-李广" aria-label="Permalink to &quot;塞上曲（李广）&quot;">​</a></h3><p><strong>出处：</strong> 《史记·李将军列传》 <strong>内容：</strong> 李广任边将，匈奴称之为&quot;飞将军&quot;。其射石搏虎的故事流传甚广，体现了汉代边塞将领的勇武精神。 <strong>原文摘录：</strong> &quot;广出猎，见草中石，以为虎而射之，中石没镞。视之，石也，因复更射之，终不能复入石矣。&quot;</p><h2 id="情谊感怀" tabindex="-1">情谊感怀 <a class="header-anchor" href="#情谊感怀" aria-label="Permalink to &quot;情谊感怀&quot;">​</a></h2><h3 id="肝胆相照" tabindex="-1">肝胆相照 <a class="header-anchor" href="#肝胆相照" aria-label="Permalink to &quot;肝胆相照&quot;">​</a></h3><p><strong>出处：</strong> 《史记·淮阴侯列传》 <strong>内容：</strong> 蒯通说韩信云：&quot;臣愿披腹心，输肝胆，效愚计。&quot;后以&quot;肝胆相照&quot;比喻以真诚之心互相照见。 <strong>原文摘录：</strong> &quot;臣愿披腹心，输肝胆，效愚计，恐足下不能用也。&quot;</p><h3 id="折戟沉沙" tabindex="-1">折戟沉沙 <a class="header-anchor" href="#折戟沉沙" aria-label="Permalink to &quot;折戟沉沙&quot;">​</a></h3><p><strong>出处：</strong> 杜牧《赤壁》 <strong>内容：</strong> 折断的兵器埋没在泥沙里。出自杜牧赤壁怀古诗，感叹历史兴亡。 <strong>原文摘录：</strong> &quot;折戟沉沙铁未销，自将磨洗认前朝。东风不与周郎便，铜雀春深锁二乔。&quot;</p><hr><p><em>本文库由 GuoAgent 运营维护</em></p>',61)])])}const c=o(s,[["render",e]]);export{d as __pageData,c as default};
